testbench:
`timescale 1ns/1ps
module tb;
  reg [15:0] a, b, c, d, e, f, g, h, i;
  reg [3:0] sel;
  wire [15:0] out;
  integer idx;

  mux9_16 dut(.a(a), .b(b), .c(c), .d(d), .e(e), .f(f), .g(g), .h(h), .i(i), .sel(sel), .out(out));

  function [15:0] expected_mux;
    input [3:0] s;
    begin
      case (s)
        4'd0: expected_mux = a;
        4'd1: expected_mux = b;
        4'd2: expected_mux = c;
        4'd3: expected_mux = d;
        4'd4: expected_mux = e;
        4'd5: expected_mux = f;
        4'd6: expected_mux = g;
        4'd7: expected_mux = h;
        4'd8: expected_mux = i;
        default: expected_mux = 16'hffff;
      endcase
    end
  endfunction

  initial begin
    a = 16'h0001;
    b = 16'h0010;
    c = 16'h0100;
    d = 16'h1000;
    e = 16'h00ff;
    f = 16'h0f0f;
    g = 16'h3333;
    h = 16'ha5a5;
    i = 16'h5a5a;

    for (idx = 0; idx < 11; idx = idx + 1) begin
      sel = idx[3:0];
      #1;
      if (out !== expected_mux(idx[3:0])) begin
        $display("FAIL sel=%0d expected=%0h got=%0h", sel, expected_mux(idx[3:0]), out);
        $fatal(1);
      end
    end

    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module mux9_16(input [15:0] a, input [15:0] b, input [15:0] c, input [15:0] d, input [15:0] e, input [15:0] f, input [15:0] g, input [15:0] h, input [15:0] i, input [3:0] sel, output reg [15:0] out);
  always @* begin
    case (sel)
      4'd0: out = a;
      4'd1: out = b;
      4'd2: out = c;
      4'd3: out = d;
      4'd4: out = e;
      4'd5: out = f;
      4'd6: out = g;
      4'd7: out = h;
      4'd8: out = i;
      default: out = 16'hffff;
    endcase
  end
endmodule
